const rows = items.map(i => i.json || {});
const now = new Date();
const today = now.toISOString().slice(0,10);
const dailyCap = Number($env.DAILY_SEND_CAP || 10);
const sentToday = rows.filter(r => String(r.last_sent_at || '').slice(0,10) === today).length;
if (sentToday >= dailyCap) return [];

const approvedRows = rows.filter(r => String(r.status || '').toUpperCase() === 'APPROVED' && String(r.approved || '').toUpperCase() === 'Y');
if (!approvedRows.length) return [];

approvedRows.sort((a,b)=> String(a.lead_id || '').localeCompare(String(b.lead_id || '')));
const lead = approvedRows[0];

const normalizedUsername = String(lead.telegram_username || lead.username || '').replace(/^@/, '');
const chatId = String(lead.telegram_chat_id || lead.telegram_user_id || '');
const draft = String(lead.draft_message || '').trim();
if (!draft) return [];

function hashText(s) {
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return String(Math.abs(h));
}

const followupCount = Number(lead.followup_count || 0);
const idem = `${lead.lead_id}-${followupCount}-${hashText(draft)}`;
if (String(lead.last_idempotency_key || '') === idem && String(lead.status || '').toUpperCase() === 'SENT') return [];

const minDelay = Number($env.SEND_DELAY_MIN_SECONDS || 180);
const maxDelay = Number($env.SEND_DELAY_MAX_SECONDS || 600);
const delay = Math.floor(Math.random() * (maxDelay - minDelay + 1)) + minDelay;
const isFollowup = !!String(lead.next_followup_at || '').trim();

return [{
  json: {
    ...lead,
    telegram_username: normalizedUsername,
    telegram_chat_id: chatId,
    followup_count: followupCount,
    is_followup: isFollowup,
    send_delay_sec: delay,
    idempotency_key: idem,
    outbound_text: draft,
  }
}];

const sec = Number($json.send_delay_sec || 180);
await new Promise(resolve => setTimeout(resolve, sec * 1000));
return items;

const lead = $items('Select Approved Lead To Send', 0, 0)[0].json;
const resolveResp = items[0].json || {};
const resolvedChatId = resolveResp.telegram_user_id || lead.telegram_chat_id || '';
const resolvedUsername = String(resolveResp.username || lead.telegram_username || '').replace(/^@/, '');
return [{ json: {
  ...lead,
  telegram_chat_id: resolvedChatId,
  telegram_username: resolvedUsername,
} }];

const lead = $items('Build Send Payload', 0, 0)[0].json;
const sendRes = items[0].json || {};
const now = new Date();
const nowIso = now.toISOString();
const minDays = Number($env.FOLLOWUP_MIN_DAYS || 2);
const maxDays = Number($env.FOLLOWUP_MAX_DAYS || 3);
const days = Math.floor(Math.random() * (maxDays - minDays + 1)) + minDays;
const next = new Date(now.getTime() + days * 24 * 60 * 60 * 1000).toISOString();
const wasFollowup = !!lead.is_followup;
const followups = Number(lead.followup_count || 0) + (wasFollowup ? 1 : 0);
const historyLine = `${nowIso}|OUTBOUND|${wasFollowup ? 'FOLLOWUP' : 'FIRST'}|${lead.outbound_text}`;
return [{ json: {
  ...lead,
  status: 'SENT',
  approved: 'N',
  error: '',
  last_error_at: '',
  last_sent_at: nowIso,
  last_message_sent: lead.outbound_text,
  last_sent_type: wasFollowup ? 'FOLLOWUP' : 'FIRST',
  next_followup_at: next,
  followup_count: followups,
  last_idempotency_key: lead.idempotency_key,
  message_history: [String(lead.message_history || ''), historyLine].filter(Boolean).join('\n')
} }];

const lead = $items('Build Send Payload', 0, 0)[0].json;
const sendRes = items[0].json || {};
const code = sendRes.result?.error_code || 'SEND_FAILED';
const nowIso = new Date().toISOString();
return [{ json: {
  ...lead,
  status: 'FAILED',
  approved: 'N',
  error: code,
  last_error_at: nowIso,
  message_history: [String(lead.message_history || ''), `${nowIso}|ERROR|${code}`].filter(Boolean).join('\n'),
  ops_failure_message: `Send failed for lead_id ${lead.lead_id}: ${code}`,
} }];

const item = $json || {};
const allowedChatId = String($env.OPS_CHAT_ID || '').trim();
let action = '';
let leadId = '';
let feedback = '';
let actor = '';
let chatId = '';
let callbackId = '';

function extractLeadIdFromCard(text) {
  const t = String(text || '');
  const m1 = t.match(/lead_id:\s*`([^`]+)`/i);
  if (m1) return String(m1[1]).trim();
  const m2 = t.match(/lead_id:\s*([^\n\s]+)/i);
  return m2 ? String(m2[1]).trim() : '';
}

if (item.callback_query) {
  const data = String(item.callback_query.data || '').trim();
  action = (data.split(':')[0] || '').toLowerCase();
  leadId = String(data.split(':')[1] || '').trim();
  if (!leadId) {
    leadId = extractLeadIdFromCard(item.callback_query.message?.text || '');
  }
  actor = String(item.callback_query.from?.username || item.callback_query.from?.id || 'unknown');
  chatId = String(item.callback_query.message?.chat?.id || '');
  callbackId = String(item.callback_query.id || '');
  if (action === 'edit') action = 'edit_request';
} else if (item.message) {
  const text = String(item.message.text || '').trim();
  actor = String(item.message.from?.username || item.message.from?.id || 'unknown');
  chatId = String(item.message.chat?.id || '');
  const low = text.toLowerCase();
  if (low === '/draftnow' || low === 'draftnow') {
    action = 'draftnow';
  } else {
    const m = text.match(/^(approve|edit|skip|dnc)\s+([^\s]+)\s*(.*)$/i);
    if (m) {
      action = m[1].toLowerCase();
      leadId = String(m[2] || '').trim();
      feedback = String(m[3] || '').trim();
      if (action === 'edit' && !feedback) action = 'edit_request';
      else if (action === 'edit' && feedback) action = 'edit_feedback';
    }
  }
}

if (allowedChatId && chatId && chatId !== allowedChatId) {
  action = '';
  leadId = '';
  feedback = '';
}

return [{ json: { action, lead_id: leadId, feedback, actor, chat_id: chatId, callback_id: callbackId } }];

const cmd = $items('Parse Ops Action', 0, 0)[0].json;
const row = items[0]?.json || {};
if (!cmd.action || !cmd.lead_id) return [];
if (!row.lead_id) {
  return [{ json: { action: cmd.action, lead_id: cmd.lead_id, ack: `Lead ${cmd.lead_id} not found.` } }];
}

const apiKey = String($env.OPENAI_API_KEY || '').trim();
const systemPrompt = String($env.OUTREACH_SYSTEM_PROMPT || '').trim() || 'Write concise human Telegram outreach. Do not invent facts.';
const safeText = (v, max = 300) => String(v ?? '').replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/[<>]/g, '').replace(/\s+/g, ' ').trim().slice(0, max);

async function rewriteDraft(existingDraft, feedback) {
  if (!apiKey || apiKey.startsWith('replace-with-')) {
    return existingDraft;
  }
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const userPrompt = `Rewrite this Telegram outreach draft using the feedback. Keep under 450 chars. One question max. No hallucinations.\nDraft: ${existingDraft}\nFeedback: ${feedback}`;
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.5,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      }),
    });
    if (!res.ok) throw new Error('rewrite_http');
    const data = await res.json();
    const msg = String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim();
    return (msg || existingDraft).slice(0, 450);
  } catch {
    return existingDraft;
  } finally {
    clearTimeout(t);
  }
}

const out = {
  ...row,
  telegram_username: row.telegram_username || row.username || '',
  telegram_chat_id: row.telegram_chat_id || row.telegram_user_id || '',
  followup_count: Number(row.followup_count || 0),
  action: cmd.action,
  lead_id: row.lead_id,
  actor: cmd.actor,
  callback_id: cmd.callback_id,
  ack: '',
  needs_approval_post: false,
};

if (cmd.action === 'approve') {
  out.status = 'APPROVED';
  out.approved = 'Y';
  out.ack = `Approved ${row.lead_id}.`;
}

if (cmd.action === 'skip') {
  const next = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
  out.status = 'FOLLOWUP_DUE';
  out.approved = 'N';
  out.next_followup_at = next;
  out.ack = `Skipped ${row.lead_id} for now. Revisit tomorrow.`;
}

if (cmd.action === 'dnc') {
  out.status = 'DNC';
  out.approved = 'N';
  out.ack = `Marked ${row.lead_id} as DNC.`;
}

if (cmd.action === 'edit_request') {
  out.status = 'NEED_EDIT';
  out.approved = 'N';
  out.ack = `Send feedback using: edit ${row.lead_id} <feedback>`;
}

if (cmd.action === 'edit_feedback') {
  const updatedDraft = await rewriteDraft(String(row.draft_message || ''), String(cmd.feedback || ''));
  out.status = 'NEED_APPROVAL';
  out.approved = 'N';
  out.approval_feedback = String(cmd.feedback || '');
  out.draft_message = updatedDraft;
  out.ack = `Rewrote draft for ${row.lead_id}. Please approve again.`;
  out.needs_approval_post = true;
  const target = out.telegram_username ? `@${String(out.telegram_username).replace(/^@/, '')}` : (out.telegram_chat_id || 'unknown_target');
  out.ops_message = [
    'Approval Required (Edited)',
    `lead_id: ${safeText(out.lead_id, 120)}`,
    `name: ${safeText(out.name || 'N/A', 120)}`,
    `target: ${safeText(target, 120)}`,
    `feedback: ${safeText(out.approval_feedback, 280)}`,
    '',
    'Draft:',
    safeText(out.draft_message, 520),
    '',
    `Text commands: approve ${safeText(out.lead_id, 120)} | edit ${safeText(out.lead_id, 120)} <feedback> | skip ${safeText(out.lead_id, 120)} | dnc ${safeText(out.lead_id, 120)}`,
  ].join('\n');
  out.cb_approve = 'approve';
  out.cb_edit = 'edit';
  out.cb_skip = 'skip';
  out.cb_dnc = 'dnc';
}

return [{ json: out }];

const evt = $items('Telegram Events Webhook', 0, 0)[0].json || {};
const allRows = items.map(i => i.json || {});
const senderId = String(evt.telegram_user_id || '').trim();
const text = String(evt.text || '').trim();
if (!senderId || !text) return [];

const lead = allRows.find(r => String(r.telegram_chat_id || r.telegram_user_id || '').trim() === senderId);
if (!lead) {
  return [{ json: { unknown_reply_alert: `Inbound reply from unknown sender ${senderId}: ${text}` } }];
}

const lower = text.toLowerCase();
const isStop = /(^|\b)(not interested|stop|don't message|do not message|unsubscribe|remove me)(\b|$)/i.test(lower);
const nowIso = new Date().toISOString();

let summary = '';
const apiKey = String($env.OPENAI_API_KEY || '').trim();
if (!isStop && apiKey && !apiKey.startsWith('replace-with-')) {
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.3,
        messages: [
          { role: 'system', content: 'Summarize lead reply in 1-3 lines: intent, objection/need, next step.' },
          { role: 'user', content: text },
        ],
      }),
    });
    if (res.ok) {
      const data = await res.json();
      summary = String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim().slice(0, 350);
    }
  } catch {
  } finally {
    clearTimeout(t);
  }
}

const nextStatus = isStop ? 'DNC' : 'REPLIED';
const historyLine = `${nowIso}|INBOUND|${text}`;
const row = {
  ...lead,
  telegram_username: lead.telegram_username || lead.username || '',
  telegram_chat_id: lead.telegram_chat_id || lead.telegram_user_id || senderId,
  status: nextStatus,
  approved: 'N',
  last_reply_received: text,
  last_reply_at: nowIso,
  memory_summary: summary || lead.memory_summary || '',
  message_history: [String(lead.message_history || ''), historyLine].filter(Boolean).join('\n'),
  ops_reply_alert: isStop
    ? `Lead ${lead.lead_id} replied stop/not interested: ${text}`
    : `New reply from lead ${lead.lead_id}: ${text}`
};

return [{ json: row }];

const rows = items.map(i => i.json || {});
const today = new Date().toISOString().slice(0,10);
const sentTodayRows = rows.filter(r => String(r.last_sent_at || '').slice(0,10) === today);
const repliesTodayRows = rows.filter(r => String(r.last_reply_at || '').slice(0,10) === today);
const failedTodayRows = rows.filter(r => String(r.last_error_at || '').slice(0,10) === today);
const followupsToday = sentTodayRows.filter(r => String(r.last_sent_type || '') === 'FOLLOWUP').length;
const sent = sentTodayRows.length;
const replies = repliesTodayRows.length;
const rate = sent > 0 ? ((replies / sent) * 100).toFixed(1) : '0.0';
const top = repliesTodayRows.slice(0,5).map(r => `- ${r.lead_id}: ${String(r.last_reply_received || '').slice(0,100)}`).join('\n');
const text = [
  '*Daily Outreach Summary*',
  `Sent today: ${sent}`,
  `Replies today: ${replies} (rate ${rate}%)`,
  `Follow-ups today: ${followupsToday}`,
  `Failed today: ${failedTodayRows.length}`,
  top ? `Top replies:\n${top}` : 'Top replies: -',
].join('\n');
return [{ json: { summary_text: text } }];

const state = $getWorkflowStaticData('global');
const offset = Number(state.ops_update_offset || 0);
return [{ json: { offset } }];

const state = $getWorkflowStaticData('global');
const payload = items[0]?.json || {};
const updates = Array.isArray(payload.result) ? payload.result : [];
if (updates.length) {
  const maxId = Math.max(...updates.map(u => Number(u.update_id || 0)));
  if (Number.isFinite(maxId) && maxId > 0) state.ops_update_offset = maxId + 1;
}
return updates.map(u => ({ json: u }));
